        "tool_args": {
          "path": "X",
          "content": null
        }
      },
      "expect": {
        "content_type": "str",
        "content_non_empty": true
      }
    },
    {
      "name": "literal_backslash_n_is_normalized",
      "input": {
        "tool_name": "append_file",
        "tool_args": {
          "path": "X",
          "content": "a\
b"
        }
      },
      "expect": {
        "contains_real_newline": true,
        "contains_literal_backslash_n": false
      }
    },
    {
      "name": "now_iso_is_resolved",
      "input": {
        "tool_name": "write_file",
        "tool_args": {
          "path": "X",
          "content": "2026-03-08T03:52:37Z"
        }
      },
      "expect": {
        "placeholder_remaining": false
      }
    }
